create database stats;
use  stats;
CREATE TABLE country_statistics (
    id INTEGER PRIMARY KEY,
    code VARCHAR(10),
    name VARCHAR(100),
    area INTEGER,
    area_land INTEGER,
    area_water INTEGER,
    population INTEGER,
    population_growth FLOAT,
    birth_rate FLOAT,
    death_rate FLOAT,
    migration_rate FLOAT
);
select * from country_statistics;
